<?php
namespace App\Http\Controllers\Proposal;
use App\Http\Controllers\Controller;use App\Http\Requests\AdminDinas\{ReviewUmkmProposalRequest,SubmitUmkmProposalRequest};use App\Models\{Umkm,UmkmUpdateSubmission};use App\Services\Audit\AuditLogger;use App\Services\Proposal\UmkmProposalService;
class UmkmProposalController extends Controller { public function create(){ return view('pages.proposals.create',['umkms'=>Umkm::query()->limit(50)->get(['id','umkm_code','business_name'])]); } public function store(SubmitUmkmProposalRequest $request, UmkmProposalService $service, AuditLogger $audit){ $umkm=Umkm::query()->findOrFail((int)$request->validated('umkm_id')); abort_if(!$request->user()->hasRole('pelaku_umkm') || !$umkm->userLinks()->where('user_id',$request->user()->id)->exists(),403); $proposal=$service->createProposal($request->validated(),$request->user()->id); $audit->log('umkm.proposal.create',$request,'umkm_update_submissions',$proposal->id,[],$proposal->toArray()); return redirect()->route('proposals.show',$proposal)->with('status','Usulan tersimpan.'); } public function indexForAdmin(){ return view('pages.proposals.admin-index',['submissions'=>UmkmUpdateSubmission::query()->latest()->paginate(30)]); } public function show(UmkmUpdateSubmission $proposal){ return view('pages.proposals.show',compact('proposal')); } public function review(ReviewUmkmProposalRequest $request, UmkmUpdateSubmission $proposal, UmkmProposalService $service, AuditLogger $audit){ abort_if($proposal->status_data==='disetujui',422,'Approved path tidak dapat diubah.'); $updated=$service->reviewProposal($proposal,$request->validated('decision'),$request->validated('review_note'),$request->user()->id,$request,$audit); return redirect()->route('admin-dinas.proposals.show',$updated)->with('status','Validasi usulan tersimpan.'); }}
